example.code:
apiVersion: argoproj.io/v1alpha1 kind: Rollout metadata: name: api spec: replicas: 5 revisionHistoryLimit: 3 selector: matchLabels: app: api template: metadata: labels: app: api spec: containers: - name: api image: registry.example.com/api:1.0.0 ports: - containerPort: 8000
strategy: canary: canaryService: api-canary stableService: api-stable trafficRouting: nginx: stableIngress: api-stable annotationPrefix: nginx.ingress.kubernetes.io
steps: # 10% for 5 minutes - setWeight: 10 - pause: {duration: 5m}
# Analysis at 10% - analysis: templates: - templateName: success-rate args: - name: service-name value: api-canary
# 30% for 5 minutes - setWeight: 30 - pause: {duration: 5m}
# 50% for 10 minutes - setWeight: 50 - pause: {duration: 10m}
# 80% for 10 minutes - setWeight: 80 - pause: {duration: 10m}
# Full promotion - setWeight: 100 --- # Analysis Template for automated validation apiVersion: argoproj.io/v1alpha1 kind: AnalysisTemplate metadata: name: success-rate spec: args: - name: service-name metrics: - name: success-rate interval: 1m count: 5 successCondition: result[0] >= 0.99 failureLimit: 3 provider: prometheus: address: http://prometheus:9090 query: | sum(rate(http_requests_total{ service="{{args.service-name}}", status=~"2.." }[5m])) / sum(rate(http_requests_total{ service="{{args.service-name}}" }[5m]))
